records.reference_model:
@startuml
enum Interval {
  weekly
  monthly
  everyHalfYear
  yearly
}
enum AccessType {
  reservable
  walkIn
  dropOff
}
enum DayOfWeek {
  Monday
  Tuesday
  Wednesday
  Thursday
  Friday
  Saturday
  Sunday
}
abstract class PersonRole {
  +idNumber: string
}
class LabTracker

class Person {
  +lastName: string
  +firstName: string
  +address: string
  +phoneNumber: string
}
class Patient {
  +dateOfBirth: string
}
class Doctor {
  +signature: string
}
class Requisition {
  +effectiveDate: string
  +repetitionCount: int
  +repetitionInterval: Interval
}
class TestResult {
  +negative: boolean
  +report: string
}
class SpecificTest {
  +date: Data
}
class Data {
}
class Appointment {
  +confirmation: string
  +date: Date
  +startTime: string
  +endTime: string
}
class BusinessHour {
  +dayOfWeek: DayOfWeek
  +startTime: string
  +endTime: string
}
class Lab {
  +registrationNumber: string
  +name: string
  +address: string
  +changeCancelFee: boolean
}
class Test {
  +name: string
  +duration: string
}
class TestType {
  +name: string
  +durationAdditive: string
  +access: AccessType
}

' Inheritance
Patient --|> PersonRole
Doctor --|> PersonRole

' Associations (containments)
LabTracker *-- Person
LabTracker *-- PersonRole
LabTracker *-- Requisition
LabTracker *-- TestResult
LabTracker *-- SpecificTest
LabTracker *-- Appointment
LabTracker *-- BusinessHour
LabTracker *-- Lab
LabTracker *-- Test
LabTracker *-- TestType

' Other associations
Person "1" -- "0..2" PersonRole
Requisition -- "*" SpecificTest
Appointment "0..*" -- "1" Lab
Doctor "1" -- "*" Requisition
Test -- "*" SpecificTest
TestType -- "*" Test
TestResult "0..1" -- "*" SpecificTest
Lab -- "7" BusinessHour
@enduml

